def lyapunov_stability_check(state: np.ndarray, P=None):
 if P is None: P = np.eye(len(state))
 V = state.T @ P @ state
 delta = np.random.normal(0, 0.01, state.shape)
 V_pert = (state + delta).T @ P @ (state + delta)
 return (V_pert - V) < 0, V
